import{_ as t,o as s,c as o,ae as r}from"./chunks/framework.DTQlDYOH.js";const p=JSON.parse('{"title":"Example: Eights (card game)","description":"","frontmatter":{},"headers":[],"relativePath":"examples/eights.md","filePath":"examples/eights.md"}'),a={name:"examples/eights.md"};function n(i,e,d,l,g,c){return s(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="example-eights-card-game" tabindex="-1">Example: Eights (card game) <a class="header-anchor" href="#example-eights-card-game" aria-label="Permalink to &quot;Example: Eights (card game)&quot;">​</a></h1><p>Eights uses personal and shared boards: hands (hidden from others), discard, stock (hidden from all), and score. Cards are dealt from stock into hands; players play or draw.</p><h2 id="entities" tabindex="-1">Entities <a class="header-anchor" href="#entities" aria-label="Permalink to &quot;Entities&quot;">​</a></h2><ul><li><strong>score</strong> — <strong>perPlayer</strong>, <strong>displayProperties</strong>: <code>[&quot;value&quot;]</code>, state <strong>value: 0</strong>.</li><li><strong>hand</strong> — <strong>type: Space</strong>, <strong>perPlayer</strong>, <strong>contentsHiddenFrom</strong>: <code>&quot;Others&quot;</code>.</li><li><strong>discard</strong> — <strong>type: Space</strong>, shared.</li><li><strong>stock</strong> — <strong>type: Space</strong>, <strong>contentsHiddenFrom</strong>: <code>&quot;All&quot;</code>.</li><li><strong>card</strong> — Many entries with <strong>value</strong> and <strong>suit</strong> (e.g. 1–13, clubs/hearts/spades/diamonds), <strong>displayProperties</strong>: <code>[&quot;value&quot;, &quot;suit&quot;]</code>.</li></ul><p><strong>sharedBoard</strong>: stock, discard. <strong>personalBoard</strong>: hand, score.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><p><strong>initialMoves</strong>: <strong>PlaceNew</strong> (matchMultiple) entities matching <strong>card</strong> into <strong>destination</strong> matching <strong>hand</strong>, with a <strong>ForEach</strong> or similar over players so each player gets a hand. Stock is filled with the remaining cards (often via <strong>TakeFrom</strong> or placement from bank).</p><h2 id="moves" tabindex="-1">Moves <a class="header-anchor" href="#moves" aria-label="Permalink to &quot;Moves&quot;">​</a></h2><p>Typical moves: <strong>TakeFrom</strong> stock → hand (draw), or <strong>PlaceNew</strong> from hand to discard (play). Legal play is usually expressed with conditions (e.g. match suit or value with top of discard). <strong>Shuffle</strong> can be used when stock is empty and discard is reshuffled.</p><p>Full definition: <code>server/eights.json</code>, <code>server/eights2.json</code>.</p>',10)])])}const m=t(a,[["render",n]]);export{p as __pageData,m as default};
